#!/usr/bin/env python3 """Ad-hoc verification: fleetctl promote + swap + benchmark_harness. Runs dry-mode checks for all new behavioral paths. No side effects on running server or model files.""" import sys, os, importlib.util, json, tempfile from pathlib import Path # helpers VERDICT = {"pass": 0, "fail": 0, "skip": 0, "detail": []} def ok(msg): VERDICT["pass"] += 1 VERDICT["detail"].append(f" {msg}") def fail(msg): VERDICT["fail"] += 1 VERDICT["detail"].append(f" {msg}") def skip(msg): VERDICT["skip"] += 1 VERDICT["detail"].append(f" {msg}") def module_path(name): p = Path(f"D:/PhronesisVault/scripts/{name}.py") return p if p.exists() else None def load_module(name): p = module_path(name) if not p: skip(f"{name}.py not found") return None spec = importlib.util.spec_from_file_location(name, p) m = importlib.util.module_from_spec(spec) try: spec.loader.exec_module(m) ok(f"{name}.py parses and imports cleanly") return m except Exception as e: fail(f"{name}.py import error: {e}") return None def subproc_ok(cmd, label, timeout=15): import subprocess try: r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout, shell=True) if r.returncode != 0: fail(f"{label} exit {r.returncode}: {r.stderr[:200]}") return None ok(f"{label} exit 0") return r.stdout except subprocess.TimeoutExpired: fail(f"{label} TIMEOUT ({timeout}s)") return None except Exception as e: fail(f"{label} exception: {e}") return None # print("=" * 62) print(" AD-HOC VERIFICATION fleetctl promote/swap + benchmark") print("=" * 62) # 1. Import parse fleetctl.promote_helpers (static parse check) # 2. Run fleetctl --help (argparse entries exist) # 3. Import benchmark harness module # 4. Verify benchmark JSON output exists & valid # 5. Run fleetctl suggest (dry uses existing data) # 6. Run fleetctl list (no model, no port uses static data) # 1. fleetctl parse + promote helpers m = load_module("fleetctl") ok("fleetctl module loaded") if m else None # 2. fleetctl --help shows ALL 9 commands out = subproc_ok( "cd /d/PhronesisVault/scripts && python fleetctl.py --help", "fleetctl --help" ) if out: expected_cmds = ["promote", "swap", "suggest", "benchmark", "reconcile", "scan", "list", "status", "info"] missing = [c for c in expected_cmds if c not in out] if missing: fail(f"Missing commands in --help: {missing}") else: ok("All 9 commands present in --help") # 3. benchmark harness module bm = load_module("model_benchmark_harness") ok("benchmark harness module loaded") if bm else None # 4. benchmark harness --list enumerates candidates out2 = subproc_ok( "cd /d/PhronesisVault/scripts && python model_benchmark_harness.py --list", "benchmark harness --list" ) if out2: lines = [l for l in out2.splitlines() if l.strip() and "unbenchmarked" in l.lower()] if lines: ok(f"Candidate enumeration: {lines[0].strip()}") # Check it returns numeric count import re nums = re.findall(r'\d+', out2) if nums and int(nums[0]) > 0: ok(f"Found {nums[0]} unbenchmarked models") # 5. fleetctl suggest out3 = subproc_ok( "cd /d/PhronesisVault/scripts && python fleetctl.py suggest", "fleetctl suggest" ) if out3: # Should name Qwythos or another candidate, not error about missing benchmark if "error" in out3.lower() and "benchmark" in out3.lower(): fail(f"suggest raises benchmark error: {out3[:200]}") else: ok("suggest runs without benchmark error") # 6. fleetctl list out4 = subproc_ok( "cd /d/PhronesisVault/scripts && python fleetctl.py list", "fleetctl list" ) if out4: if "qwen" in out4.lower() or "qwythos" in out4.lower() or "llama" in out4.lower(): ok("list returns model names") else: fail(f"list output suspicious no model names: {out4[:200]}") # 7. fleetctl info (on a known model) out5 = subproc_ok( "cd /d/PhronesisVault/scripts && python fleetctl.py info qwythos-9b-abliterated-q6_k.gguf", "fleetctl info qwythos" ) if out5: if "candidate" in out5.lower() or "benchmark" in out5.lower() or "lifecycle" in out5.lower(): ok("info returns lifecycle/benchmark data") else: fail(f"info output missing expected fields: {out5[:200]}") # 8. Verify benchmark JSON files exist and parse valid bench_dir = Path("D:/PhronesisVault/Operations/benchmark-results") if bench_dir.exists(): ok("benchmark-results/ directory exists") jsons = list(bench_dir.glob("*.json")) if jsons: ok(f"Found {len(jsons)} benchmark JSON files") for jf in jsons: try: data = json.loads(jf.read_text()) if "model" in data and "tests" in data and "composite_score" in data: ok(f" {jf.name}: {data['model']} {data.get('pass_rate','?'):%} pass, composite {data.get('composite_score','?')}") else: skip(f" {jf.name}: missing expected fields (old format?)") except json.JSONDecodeError: fail(f" {jf.name}: invalid JSON") else: fail("benchmark-results/ empty no JSON files") else: fail("benchmark-results/ directory missing") # 9. Tiered-context-benchmark exists tc = Path("D:/PhronesisVault/Operations/tiered-context-benchmark.jsonl") ok("tiered-context-benchmark.jsonl exists") if tc.exists() else fail("tiered-context-benchmark.jsonl missing") # print("\n" + "=" * 62) print(f" RESULT: {VERDICT['pass']} passed, {VERDICT['fail']} failed, {VERDICT['skip']} skipped") print("=" * 62) for d in VERDICT["detail"]: print(d) print("=" * 62) # Exit code sys.exit(1 if VERDICT["fail"] > 0 else 0)